    31→export default function SignInPage() {
    32→  const [isLoading, setIsLoading] = useState(false);
    33→  const [callbackUrl, setCallbackUrl] = useState<string | null>(null);
    34→
    35→  useEffect(() => {
    36→    if (!getIsClient()) return;
    37→
    38→    const params = new URLSearchParams(window.location.search);
    39→    setCallbackUrl(params.get("callbackUrl"));
    40→  }, []);
    41→
    42→  const form = useForm<LoginFormData>({
    43→    resolver: zodResolver(loginSchema),
    44→    defaultValues: {
    45→      email: "",
    46→      password: "",
    47→    },
    48→  });
    49→
    50→  const onSubmit = async (data: LoginFormData) => {
    51→    setIsLoading(true);
    52→
    53→    try {
    54→      const result = await signIn("credentials", {
    55→        email: data.email,
    56→        password: data.password,
    57→        redirect: false,
    58→      });
