    60→      if (result?.error) {
    61→        toast.error("Sign In Failed", {
    62→          description: "Invalid email or password",
    63→        });
    64→
    65→        return;
    66→      }
    67→
    68→      if (result?.ok) {
    69→        const redirectUrl = callbackUrl || APP_ROUTES.PROFILE;
    70→        hardPush(redirectUrl);
    71→      }
    72→    } catch {
    73→      toast.error("Sign In Failed", {
    74→        description: "An unexpected error occurred",
