    98→                <FormItem className="w-full">
    99→                  <FormLabel className="text-base leading-[1.222em] sm:text-lg">
   100→                    Email
   101→                  </FormLabel>
   102→                  <FormControl>
   103→                    <Input
   104→                      placeholder="Enter Your Email"
   105→                      type="email"
   106→                      className="h-10 rounded-lg"
   107→                      {...field}
   108→                    />
   109→                  </FormControl>
   110→                  <FormMessage />
   111→                </FormItem>
   112→              )}
   113→            />
   114→
   115→            {/* Password */}
   116→            <FormField
   117→              control={form.control}
   118→              name="password"
   119→              render={({ field }) => (
   120→                <FormItem className="w-full">
   121→                  <FormLabel className="text-base leading-[1.222em] sm:text-lg">
   122→                    Password
   123→                  </FormLabel>
   124→                  <FormControl>
   125→                    <PasswordInput placeholder="Password" {...field} />
   126→                  </FormControl>
   127→                  <Link
   128→                    href={APP_ROUTES.AUTH.REQUEST_FORGOT_PASSWORD}
