   130→                  >
   131→                    Forgot Password ?
   132→                  </Link>
   133→                  <FormMessage />
   134→                </FormItem>
   135→              )}
   136→            />
   137→          </div>
   138→
   139→          {/* Submit Button */}
   140→          <Button
   141→            type="submit"
   142→            disabled={isLoading}
   143→            className="w-full rounded-xl px-6 py-[11px] font-bold font-serif text-base leading-[1.199em] sm:w-fit sm:px-[58px] sm:text-lg"
   144→          >
   145→            {isLoading ? "Signing In..." : "Sign In"}
   146→          </Button>
   147→
   148→          {/* Social Login Options */}
   149→          <div className="flex w-full flex-col items-center gap-3 sm:gap-[15px]">
   150→            {/* <div className="flex w-full flex-col items-center gap-[15px]">
   151→              <Button
   152→                type="button"
   153→                variant="outline"
   154→                className="h-10 w-full max-w-[350px] justify-center gap-2.5 rounded-[10px] px-2.5 py-[5px] font-serif text-sm leading-[1.199em]"
   155→              >
   156→                <UaePassIcon className="size-4 shrink-0" />
   157→                <span className="truncate">Continue with UAE pass</span>
   158→              </Button>
   159→
   160→              <Button
   161→                type="button"
   162→                variant="outline"
   163→                className="h-10 w-full max-w-[350px] justify-center gap-2.5 rounded-[10px] px-2.5 py-[5px] font-serif text-sm leading-[1.199em]"
   164→              >
   165→                <GoogleIcon className="size-4 shrink-0" />
   166→                <span className="truncate">Continue with Google</span>
   167→              </Button>
   168→
   169→              <Button
   170→                type="button"
   171→                variant="outline"
   172→                className="h-10 w-full max-w-[350px] justify-center gap-2.5 rounded-[10px] px-2.5 py-[5px] font-serif text-sm leading-[1.199em]"
   173→              >
   174→                <AppleIcon className="size-4 shrink-0" />
   175→                <span className="truncate">Continue with Apple ID</span>
   176→              </Button>
   177→            </div> */}
   178→
   179→            <Link
   180→              href={APP_ROUTES.AUTH.SIGN_UP}
   181→              className="text-center font-serif text-sm leading-[1.199em] transition-opacity hover:opacity-70"
   182→            >
   183→              Not register yet Create account
   184→            </Link>
