     8→export default async function SignupPage() {
     9→  const queryClient = getQueryClientServer();
    10→
    11→  await queryClient.prefetchQuery({
    12→    queryKey: ApiKeys.countries(),
    13→    queryFn: getCountries,
    14→    staleTime: 60 * 60 * 24,
