     9→
    10→import { sendOtp } from "@/entities/auth/api/services";
    11→import {
    12→  useCheckEmailExists,
    13→  useCheckPhoneExists,
    14→} from "@/shared/api/query-hooks/use-auth-checks";
    15→import { APP_ROUTES } from "@/shared/config/app-routes";
    16→import {
    17→  USER_ROLES,
    18→  USER_ROLES_ARRAY,
    19→  type UserRole,
    20→} from "@/shared/constants";
    21→import { authStorage } from "@/shared/lib/storage/auth-storage";
    22→import { MediaType, OtpType } from "@/shared/types/auth.types";
    23→import { Button } from "@/shared/ui/button";
    24→import { Form } from "@/shared/ui/form/form";
    25→import { FormControl } from "@/shared/ui/form/form-control";
    26→import { FormField } from "@/shared/ui/form/form-field";
    27→import { FormItem } from "@/shared/ui/form/form-item";
    28→import { FormLabel } from "@/shared/ui/form/form-label";
    29→import { FormMessage } from "@/shared/ui/form/form-message";
    30→import { Input } from "@/shared/ui/input";
    31→import { toast } from "@/shared/ui/notification";
    32→import { PhoneInput } from "@/shared/ui/phone-input";
    33→import { Tabs, TabsList, TabsTrigger } from "@/shared/ui/tabs";
    34→
    35→const signupSchema = z.object({
    36→  role: z.enum(USER_ROLES_ARRAY as [string, ...string[]], {
    37→    required_error: "Please select a role",
    38→  }),
    39→  fullName: z.string().min(2, "Full name must be at least 2 characters"),
    40→  email: z.string().email("Please enter a valid email"),
    41→  phone: z.string().min(10, "Phone number must be at least 10 digits"),
    42→  hasReferralCode: z.boolean(),
    43→  referralCode: z.string().optional(),
    44→});
    45→
    46→type SignupFormData = z.infer<typeof signupSchema>;
    47→
    48→export function SignupForm() {
    49→  const router = useRouter();
    50→
    51→  const [selectedRole, setSelectedRole] = useState<UserRole>(USER_ROLES.SELLER);
    52→  const [_hasReferralCode, setHasReferralCode] = useState(false);
    53→  const [isLoading, setIsLoading] = useState(false);
    54→
    55→  const checkEmailExists = useCheckEmailExists();
    56→  const checkPhoneExists = useCheckPhoneExists();
    57→
    58→  const form = useForm<SignupFormData>({
    59→    resolver: zodResolver(signupSchema),
    60→    defaultValues: {
    61→      role: USER_ROLES.SELLER,
    62→      fullName: "",
    63→      email: "",
    64→      phone: "",
    65→      hasReferralCode: false,
    66→      referralCode: "",
    67→    },
    68→  });
    69→
    70→  const onSubmit = async (data: SignupFormData) => {
    71→    setIsLoading(true);
    72→
    73→    try {
    74→      const [emailCheckResult, phoneCheckResult] = await Promise.all([
    75→        checkEmailExists.mutateAsync(data.email),
    76→        checkPhoneExists.mutateAsync(data.phone),
    77→      ]);
    78→
    79→      let hasErrors = false;
    80→
    81→      if (emailCheckResult.exists) {
    82→        form.setError("email", {
    83→          type: "manual",
    84→          message:
    85→            "This email is already registered. Please use a different email or sign in.",
    86→        });
    87→        hasErrors = true;
    88→      }
    89→
    90→      if (phoneCheckResult.exists) {
    91→        form.setError("phone", {
    92→          type: "manual",
    93→          message:
    94→            "This phone number is already registered. Please use a different number or sign in.",
    95→        });
    96→        hasErrors = true;
    97→      }
    98→
    99→      if (hasErrors) {
   100→        setIsLoading(false);
   101→
   102→        return;
   103→      }
   104→
   105→      const [emailOtpResponse, phoneOtpResponse] = await Promise.all([
   106→        sendOtp({
   107→          email: data.email,
   108→          type: OtpType.SIGN_UP,
   109→          mediaType: MediaType.EMAIL,
   110→        }),
   111→        sendOtp({
   112→          phone: data.phone,
   113→          type: OtpType.SIGN_UP,
   114→          mediaType: MediaType.PHONE,
   115→        }),
   116→      ]);
   117→
   118→      authStorage.signup.set({
   119→        email: data.email,
   120→        phone: data.phone,
   121→        fullName: data.fullName,
   122→        role: data.role,
   123→        referralCode: data.referralCode,
   124→        devEmailOtp: emailOtpResponse.otp,
   125→        devPhoneOtp: phoneOtpResponse.otp,
   126→      });
   127→
   128→      if (emailOtpResponse.otp || phoneOtpResponse.otp) {
   129→        toast.success("OTP Generated", {
   130→          description: "Check the verification page for your OTP codes",
   131→        });
   132→      } else {
   133→        toast.success("OTP Sent", {
   134→          description: "Please check your email and phone for OTP codes",
   135→        });
   136→      }
   137→
   138→      router.push(APP_ROUTES.AUTH.VERIFY_OTP);
   139→    } catch {
   140→      toast.error("Failed to Send OTP", {
   141→        description: "Please try again later",
   142→      });
   143→    } finally {
   144→      setIsLoading(false);
   145→    }
   146→  };
   147→
   148→  const handleRoleChange = (value: string) => {
   149→    const role = value as UserRole;
   150→    setSelectedRole(role);
   151→    form.setValue("role", role);
   152→    setHasReferralCode(false);
   153→    form.setValue("hasReferralCode", false);
   154→    form.setValue("referralCode", "");
   155→  };
   156→
   157→  return (
   158→    <div className="flex w-full flex-col gap-6">
   159→      <h1 className="text-center font-bold font-serif text-2xl leading-[1.199em]">
   160→        Create an Account
   161→      </h1>
   162→
   163→      <Form {...form}>
   164→        <form
   165→          onSubmit={form.handleSubmit(onSubmit)}
   166→          className="flex w-full flex-col items-center gap-9"
   167→        >
   168→          <div className="flex w-full flex-col items-center justify-center gap-[14px]">
   169→            <Tabs
   170→              value={selectedRole}
   171→              onValueChange={handleRoleChange}
   172→              className="w-full"
   173→            >
   174→              <TabsList variant="default" className="w-full">
   175→                <TabsTrigger
   176→                  variant="default"
   177→                  value={USER_ROLES.SELLER}
   178→                  className="border border-[#C1C7CD]"
   179→                >
   180→                  Seller
   181→                </TabsTrigger>
   182→                {/* Not in MVP:
   183→                <TabsTrigger
   184→                  variant="default"
   185→                  value={USER_ROLES.BIDDER}
   186→                  className="border border-[#C1C7CD]"
   187→                >
   188→                  Bidder
   189→                </TabsTrigger>
   190→                <TabsTrigger
   191→                  variant="default"
   192→                  value={USER_ROLES.RETAILER}
   193→                  className="border border-[#C1C7CD]"
   194→                >
   195→                  Retailer
   196→                </TabsTrigger>
   197→                */}
   198→              </TabsList>
   199→            </Tabs>
   200→
   201→            <FormField
   202→              control={form.control}
   203→              name="fullName"
   204→              render={({ field }) => (
   205→                <FormItem className="w-full">
   206→                  <FormLabel>Full Name</FormLabel>
   207→                  <FormControl>
   208→                    <Input
   209→                      placeholder="Enter Your Name as per Documents"
   210→                      className="h-10"
   211→                      {...field}
   212→                    />
   213→                  </FormControl>
   214→                  <FormMessage />
   215→                </FormItem>
   216→              )}
   217→            />
   218→
   219→            <FormField
   220→              control={form.control}
   221→              name="phone"
   222→              render={({ field }) => (
   223→                <FormItem className="w-full">
   224→                  <FormLabel>Phone number</FormLabel>
   225→                  <FormControl>
   226→                    <PhoneInput
   227→                      defaultCountryAlpha2="UA"
   228→                      placeholder="Eg. 501234567"
   229→                      {...field}
   230→                    />
   231→                  </FormControl>
   232→                  <p className="font-serif text-foreground text-xs">
   233→                    Enter a valid Phone number, you will receive an OTP to
   234→                    verify your Phone Number.
   235→                  </p>
   236→                  <FormMessage />
   237→                </FormItem>
   238→              )}
   239→            />
   240→
   241→            <FormField
   242→              control={form.control}
   243→              name="email"
   244→              render={({ field }) => (
   245→                <FormItem className="w-full">
   246→                  <FormLabel>Email</FormLabel>
   247→                  <FormControl>
   248→                    <Input
   249→                      placeholder="Enter Your Email"
   250→                      type="email"
   251→                      className="h-10"
   252→                      {...field}
   253→                    />
   254→                  </FormControl>
   255→                  <p className="font-serif text-foreground text-xs">
   256→                    Enter a valid email, you will receive an OTP to verify your
   257→                    email.
   258→                  </p>
   259→                  <FormMessage />
   260→                </FormItem>
   261→              )}
   262→            />
   263→
