     1→import type { NextAuthOptions, User } from "next-auth";
     2→import type { JWT } from "next-auth/jwt";
     3→import CredentialsProvider from "next-auth/providers/credentials";
     4→
     5→import { signIn } from "@/entities/auth/api/services";
     6→import { getProfileWithToken } from "@/entities/profile/api/services";
     7→import { calculateExpiresIn } from "@/shared/lib/auth";
     8→import type { RefreshTokenResponse } from "@/shared/types/auth.types";
     9→
    10→import { API_ROUTES } from "./api-routes";
    11→import { APP_ROUTES } from "./app-routes";
    12→import { ENV } from "./env";
    13→
    14→const AUTH_TOKEN_LIFETIME_TO_REFRESH = 60;
    15→const REFRESH_TOKEN_EXPIRATION_TIME = 24 * 60 * 60 * 1000;
    16→
    17→export const authConfig: NextAuthOptions = {
    18→  secret: ENV.NEXTAUTH_SECRET,
    19→  providers: [
    20→    CredentialsProvider({
    21→      id: "credentials",
    22→      name: "Credentials",
    23→      credentials: {
    24→        email: { label: "Email", type: "text" },
    25→        password: { label: "Password", type: "password" },
    26→      },
    27→      authorize: async (credentials): Promise<null | User> => {
    28→        if (!(credentials?.email && credentials?.password)) return null;
    29→
    30→        try {
    31→          const response = await signIn({
    32→            email: credentials.email,
    33→            password: credentials.password,
    34→          });
    35→
    36→          if (
    37→            response.status === "CHALLENGE" &&
    38→            response.challengeName === "NEW_PASSWORD_REQUIRED"
    39→          ) {
    40→            return {
    41→              id: "",
    42→              email: credentials.email,
    43→              accessToken: "",
    44→              refreshToken: "",
    45→              idToken: "",
    46→              isTemporaryPassword: true,
    47→              tempPasswordSession: response.session,
    48→            };
    49→          }
    50→
    51→          if (response.status === "SUCCESS") {
    52→            const { payload } = response;
    53→
    54→            const profile = await getProfileWithToken(payload.accessToken);
    55→
    56→            return {
    57→              id: profile.id,
    58→              email: profile.email,
    59→              accessToken: payload.accessToken,
    60→              refreshToken: payload.refreshToken,
    61→              idToken: payload.idToken,
    62→              refreshTokenExpiresAt: Date.now() + REFRESH_TOKEN_EXPIRATION_TIME,
    63→              profile,
    64→            };
    65→          }
    66→
    67→          console.error("Error signing in:", response);
    68→
    69→          return null;
    70→        } catch (e) {
    71→          console.error("Error signing in:", e);
    72→          return null;
    73→        }
    74→      },
    75→    }),
    76→  ],
    77→
    78→  callbacks: {
    79→    async jwt({ token, user, account, trigger, session }): Promise<JWT> {
    80→      const isManualUpdate = trigger === "update" && session;
    81→
    82→      if (isManualUpdate) {
    83→        return {
    84→          ...token,
    85→          ...session,
    86→        };
    87→      }
    88→
    89→      if (account && user) {
    90→        token.id = user.id;
    91→        token.email = user.email;
    92→        token.accessToken = user.accessToken;
    93→        token.refreshToken = user.refreshToken;
    94→        token.idToken = user.idToken;
    95→        token.refreshTokenExpiresAt = user.refreshTokenExpiresAt;
    96→        token.session = user.session;
    97→        token.profile = user.profile;
    98→        token.isTemporaryPassword = user.isTemporaryPassword;
    99→        token.tempPasswordSession = user.tempPasswordSession;
   100→      }
   101→
   102→      const expiresIn = calculateExpiresIn(token.accessToken);
   103→
   104→      if (expiresIn < AUTH_TOKEN_LIFETIME_TO_REFRESH && token.refreshToken) {
   105→        const newAccessToken = await refreshAccessToken(
   106→          token.refreshToken,
   107→          token.accessToken,
   108→        );
   109→
   110→        if (newAccessToken) {
   111→          token.accessToken = newAccessToken.accessToken;
   112→          token.refreshToken = newAccessToken.refreshToken;
   113→          token.idToken = newAccessToken.idToken;
   114→        }
   115→      }
   116→
   117→      return token;
   118→    },
   119→
   120→    async session({ session, token }) {
   121→      if (token) {
   122→        session.accessToken = token.accessToken;
   123→        session.refreshToken = token.refreshToken;
   124→        session.idToken = token.idToken;
   125→        session.refreshTokenExpiresAt = token.refreshTokenExpiresAt;
   126→        session.session = token.session;
   127→        session.isTemporaryPassword = token.isTemporaryPassword;
   128→        session.tempPasswordSession = token.tempPasswordSession;
   129→        session.user = {
   130→          id: token.id,
   131→          email: token.email,
   132→          profile: token.profile,
   133→        };
   134→      }
   135→
   136→      return session;
   137→    },
   138→
   139→    async signIn() {
   140→      return true;
   141→    },
   142→  },
   143→
   144→  pages: {
   145→    signIn: APP_ROUTES.AUTH.SIGN_IN,
   146→  },
   147→
   148→  session: {
   149→    strategy: "jwt",
   150→    maxAge: 30 * 24 * 60 * 60,
   151→  },
   152→};
   153→
   154→async function refreshAccessToken(
   155→  refreshTokenValue: string,
   156→  accessTokenValue: string,
   157→) {
   158→  try {
   159→    const url = `${ENV.NEXT_PUBLIC_APP_API_URL}${API_ROUTES.AUTH.REFRESH_TOKEN}`;
   160→    const response = await fetch(url, {
   161→      method: "POST",
   162→      headers: {
   163→        "Content-Type": "application/json",
   164→      },
   165→      body: JSON.stringify({
   166→        refreshToken: refreshTokenValue,
   167→        accessToken: accessTokenValue,
   168→      }),
   169→    });
   170→
   171→    if (!response.ok) {
   172→      throw new Error("Failed to refresh access token");
   173→    }
   174→
   175→    const result = (await response.json()) as RefreshTokenResponse;
   176→
   177→    return {
   178→      accessToken: result.accessToken,
   179→      refreshToken: result.refreshToken,
   180→      idToken: result.idToken,
   181→    };
   182→  } catch (error) {
   183→    console.error("Failed to refresh access token:", error);
   184→    return null;
   185→  }
   186→}
